// ===== 핵심: 로비 매칭 시스템 =====
public class LobbyMatchmaker : NetworkBehaviour
{
    [Networked, Capacity(50)] 
    public NetworkArray<PlayerRef> WaitingQueue { get; }

    [Networked] public int QueueCount { get; set; }

    // 매칭 대기열에 참가
    public void JoinQueue()
    {
        RPC_RequestJoinQueue(Runner.LocalPlayer);
    }

    [Rpc(RpcSources.InputAuthority, RpcTargets.StateAuthority)]
    void RPC_RequestJoinQueue(PlayerRef player)
    {
        // 대기열에 추가
        for (int i = 0; i < WaitingQueue.Length; i++)
        {
            if (!WaitingQueue[i].IsValid)
            {
                WaitingQueue.Set(i, player);
                QueueCount++;
                break;
            }
        }

        Debug.Log($"[Lobby] 대기열 참가: {player} (총 {QueueCount}명 대기 중)");

        // 2명 이상이면 즉시 매칭!
        if (QueueCount >= 2)
        {
            CreateMatch();
        }
    }

    // 2명씩 매칭해서 게임방 생성
    private void CreateMatch()
    {
        PlayerRef player1 = PlayerRef.None;
        PlayerRef player2 = PlayerRef.None;

        // 대기열에서 2명 뽑기
        int found = 0;
        for (int i = 0; i < WaitingQueue.Length && found < 2; i++)
        {
            if (WaitingQueue[i].IsValid)
            {
                if (found == 0) player1 = WaitingQueue[i];
                else player2 = WaitingQueue[i];

                WaitingQueue.Set(i, PlayerRef.None); // 대기열에서 제거
                found++;
                QueueCount--;
            }
        }

        if (found == 2)
        {
            string roomId = $"Room_{Random.Range(1000, 9999)}";
            Debug.Log($"[Lobby] 매칭 성공! {player1} vs {player2} → {roomId}");

            // 매칭된 2명에게만 게임방 입장 명령!
            RPC_EnterGameRoom(roomId, player1, player2);
        }
    }

    // 매칭된 2명만 게임방으로!
    [Rpc(RpcSources.StateAuthority, RpcTargets.Specified)]
    void RPC_EnterGameRoom(NetworkString<_16> roomId, PlayerRef player1, PlayerRef player2,
                          RpcTargetUse targets = RpcTargetUse.Specified)
    {
        Debug.Log($"[매칭완료] {roomId} 입장!");

        // 로비 UI 숨기기
        FindObjectOfType<LobbyUI>()?.Hide();

        // 게임 씬을 Additive로 로드!
        StartCoroutine(LoadGameSceneAdditive(roomId.ToString()));
    }

    // 핵심! Additive 씬 로딩
    private IEnumerator LoadGameSceneAdditive(string roomId)
    {
        Debug.Log($"[씬로딩] {roomId}용 게임 씬을 Additive로 로드 중...");

        // 게임 씬을 추가로 로드 (로비 씬은 그대로!)
        var operation = SceneManager.LoadSceneAsync("GameScene", LoadSceneMode.Additive);

        while (!operation.isDone)
        {
            yield return null;
        }

        // 로드된 게임 씬에서 게임 시작
        var gameScene = SceneManager.GetSceneByName("GameScene");
        var gameObjects = gameScene.GetRootGameObjects();

        foreach (var obj in gameObjects)
        {
            var gameController = obj.GetComponent<GameController>();
            if (gameController != null)
            {
                gameController.StartGame(roomId);
                break;
            }
        }

        Debug.Log($"[씬로딩 완료] {roomId} 게임 시작!");
    }
}

// ===== 게임 컨트롤러 (게임 씬 안에 있음) =====
public class GameController : MonoBehaviour
{
    private string currentRoomId;

    public void StartGame(string roomId)
    {
        currentRoomId = roomId;
        Debug.Log($"[게임시작] {roomId}에서 오목 게임 시작!");

        // 오목 게임 초기화
        InitializeOmokGame();
    }

    private void InitializeOmokGame()
    {
        // 오목판 생성, 카메라 설정 등...
        Debug.Log("[오목] 게임 준비 완료!");
    }

    // 게임 종료 시
    public void EndGame(string winner)
    {
        Debug.Log($"[게임종료] {winner} 승리!");

        StartCoroutine(ReturnToLobby());
    }

    private IEnumerator ReturnToLobby()
    {
        yield return new WaitForSeconds(3f);

        Debug.Log("[복귀] 로비로 돌아가는 중...");

        // 게임 씬만 언로드 (로비는 그대로!)
        var gameScene = SceneManager.GetSceneByName("GameScene");
        await SceneManager.UnloadSceneAsync(gameScene);

        // 로비 UI 다시 표시
        FindObjectOfType<LobbyUI>()?.Show();

        Debug.Log("[복귀완료] 로비로 돌아왔습니다!");
    }
}

// ===== 간단한 UI =====
public class LobbyUI : MonoBehaviour
{
    [SerializeField] private GameObject lobbyPanel;
    [SerializeField] private Button matchButton;
    [SerializeField] private Text queueText;

    void Start()
    {
        matchButton.onClick.AddListener(() => {
            FindObjectOfType<LobbyMatchmaker>()?.JoinQueue();
        });
    }

    void Update()
    {
        var matchmaker = FindObjectOfType<LobbyMatchmaker>();
        if (matchmaker != null)
        {
            queueText.text = $"대기 중: {matchmaker.QueueCount}명";
        }
    }

    public void Hide() => lobbyPanel.SetActive(false);
    public void Show() => lobbyPanel.SetActive(true);
}
